import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"SKAdNetwork Direct Postback","description":"","frontmatter":{"title":"SKAdNetwork Direct Postback","slug":"skadnetwork-direct-postback"},"headers":[],"relativePath":"marketer-hub/skadnetwork-direct-postback.md","filePath":"marketer-hub/skadnetwork-direct-postback.md"}'),r={name:"marketer-hub/skadnetwork-direct-postback.md"};function s(n,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>For iOS 15+ devices, advertiser apps can now receive the winning SKAdNetwork (SKAN) postback if they include <a href="https://developer.apple.com/documentation/bundleresources/information_property_list/nsadvertisingattributionreportendpoint" target="_blank" rel="noreferrer">NSAdvertisingAttributionReportEndpoint</a> in your app&#39;s Info.plist. This will allow you to send that postback to Branch.</p><p>Previously, Postbacks were only sent directly to ad networks who would then forward them to advertisers and/or MMPs. With Direct Postback, marketers will be able to validate if the received data from networks is complete when looking at the total. Branch offers an endpoint URL that marketers can use to send a copy of these postbacks to Branch that can then be exposed via the Custom Exports API.</p><h3 id="benefits-of-direct-postback" tabindex="-1">Benefits of Direct Postback <a class="header-anchor" href="#benefits-of-direct-postback" aria-label="Permalink to &quot;Benefits of Direct Postback&quot;">​</a></h3><ul><li><p>Postbacks received will go through an additional validation process to ensure that the postback came from Apple.</p></li><li><p>Postbacks contain the Conversion Value critical to advertisers that are used to measure user quality</p></li><li><p>Gain access to all the winning postbacks, including those that were sent to Facebook and Google which only share aggregate numbers</p></li><li><p>View redownload metrics</p><ul><li>Some ad networks (Google, Facebook, Snap) don&#39;t share redownload data with Branch</li></ul></li><li><p>Full visibility into publisher level reporting</p></li><li><p>View touch-type engagement &amp; Conversion Value mapping</p><ul><li>Lower and Upper revenue value mapping</li><li>Customer event alias mapping</li></ul></li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Direct Postback, you need to have completed the following:</p><ol><li><a href="./enable-skadnetwork.html">Implemented SKAdNetwork</a></li><li>Running SKAdNetwork campaigns</li></ol><h2 id="enable-direct-postback" tabindex="-1">Enable Direct Postback <a class="header-anchor" href="#enable-direct-postback" aria-label="Permalink to &quot;Enable Direct Postback&quot;">​</a></h2><h3 id="_1-add-the-branch-skadnetwork-endpoint" tabindex="-1">1. Add the Branch SKAdNetwork Endpoint <a class="header-anchor" href="#_1-add-the-branch-skadnetwork-endpoint" aria-label="Permalink to &quot;1. Add the Branch SKAdNetwork Endpoint&quot;">​</a></h3><p>Have the iOS Development team use the <code>NSAdvertisingAttributionReportEndpoint</code> framework in your app&#39;s Info.plist adding the following Branch endpoint:</p><p><code>https://branch-skan.com</code></p><h3 id="_2-export-the-postbacks" tabindex="-1">2. Export the Postbacks <a class="header-anchor" href="#_2-export-the-postbacks" aria-label="Permalink to &quot;2. Export the Postbacks&quot;">​</a></h3><p>Using Branch&#39;s <a href="./custom-exports-api.html">Custom Exports API</a>, run an export to see postback data via the new topics:</p><ul><li><code>skadnetwork_invalid_messages</code></li><li><code>skadnetwork_valid_messages</code></li></ul><p>Additional details on the fields of the above topics can be found <a href="./custom-exports-api.html">here</a>.</p><p>There is a new parameter called <code>advertiser_copy</code> in the Export API which will be &#39;true&#39; when the corresponding SKAN data is received from the advertiser app directly for ease of filtering.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="will-this-cause-duplicates-in-my-reports" tabindex="-1">Will this cause duplicates in my reports? <a class="header-anchor" href="#will-this-cause-duplicates-in-my-reports" aria-label="Permalink to &quot;Will this cause duplicates in my reports?&quot;">​</a></h4><p>No. The Branch Dashboard will filter the ad partner copies to avoid duplication, but exports will show the copies. Be sure to filter your export results using the <code>advertiser_copy</code> parameter.</p><h4 id="is-there-still-value-in-postbacks-from-the-ad-network" tabindex="-1">Is there still value in postbacks from the ad network? <a class="header-anchor" href="#is-there-still-value-in-postbacks-from-the-ad-network" aria-label="Permalink to &quot;Is there still value in postbacks from the ad network?&quot;">​</a></h4><p>Yes. The advertiser will still depend on the ad network to decode some data. For example, only the ad network can map the SKAN Campaign ID to the Campaign Name. Additionally, ad networks can receive non-winning postbacks if they had a SKAN ad touch from a user that converted, providing some multi-touch data not available in Apple&#39;s direct postbacks.</p><h4 id="will-postbacks-be-sent-to-devices-ios-15" tabindex="-1">Will postbacks be sent to devices &lt; iOS 15? <a class="header-anchor" href="#will-postbacks-be-sent-to-devices-ios-15" aria-label="Permalink to &quot;Will postbacks be sent to devices &lt; iOS 15?&quot;">​</a></h4><p>No. Apple will only send additional postbacks for devices running iOS 15+.</p>',24)])])}const k=t(r,[["render",s]]);export{u as __pageData,k as default};
